use std::cell::{Cell, RefCell};

// Cell<T>: for Copy types, get/set without borrowing
struct CallCounter {
    count: Cell<u32>,
}

impl CallCounter {
    fn new() -> Self {
        CallCounter { count: Cell::new(0) }
    }

    fn increment(&self) {  // Note: &self, not &mut self
        self.count.set(self.count.get() + 1);
    }

    fn get(&self) -> u32 {
        self.count.get()
    }
}

// RefCell<T>: for non-Copy types, borrow-checked at runtime
struct Logger {
    messages: RefCell<Vec<String>>,
}

impl Logger {
    fn new() -> Self {
        Logger { messages: RefCell::new(Vec::new()) }
    }

    fn log(&self, msg: &str) {  // &self, not &mut self
        self.messages.borrow_mut().push(msg.to_string());
    }

    fn dump(&self) {
        for msg in self.messages.borrow().iter() {
            println!("  LOG: {}", msg);
        }
    }
}

// Thread-safe version with Arc + Mutex
use std::sync::{Arc, Mutex};

fn threaded_counter() {
    let counter = Arc::new(Mutex::new(0u64));
    let mut handles = vec![];

    for _ in 0..5 {
        let counter = Arc::clone(&counter);
        handles.push(std::thread::spawn(move || {
            let mut num = counter.lock().unwrap();
            *num += 1;
        }));
    }

    for h in handles { h.join().unwrap(); }
    println!("Counter: {}", *counter.lock().unwrap());
}

fn main() {
    let counter = CallCounter::new();
    counter.increment();
    counter.increment();
    println!("Calls: {}", counter.get());

    let logger = Logger::new();
    logger.log("Started");
    logger.log("Processing");
    logger.dump();

    threaded_counter();
}
